-- ───────────────────────────────────────────────────────────────────────────── -- schema.sql -- -- MySQL 8 schema for the stock-performance database. -- Mounted to /docker-entrypoint-initdb.d/ so MySQL executes this file -- automatically the first time the container starts with an empty data volume. -- -- Design decisions: -- • utf8mb4 / utf8mb4_unicode_ci – full Unicode support, including emoji in names -- • DECIMAL(14,4) for prices – exact arithmetic; avoids floating-point drift -- • UNIQUE KEY on (id_stock, price_date) – prevents duplicate daily records -- • Foreign key from stock_prices → stock_identifiers – referential integrity -- • ON DELETE CASCADE – removing an identifier removes its prices automatically -- • InnoDB engine – supports transactions & foreign keys -- ─────────────────────────────────────────────────────────────────────────────
CREATE DATABASE IF NOT EXISTS stockdb CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE stockdb;
-- ── Table: stock_identifiers ───────────────────────────────────────────────── -- Maps a numeric id_stock to a human-readable name and ticker symbol. -- id_stock values in the CSV use quoted comma formatting (e.g. "40,359,100"); -- the Java loader strips the commas before inserting. -- ──────────────────────────────────────────────────────────────────────────── CREATE TABLE IF NOT EXISTS stock_identifiers ( id_stock BIGINT NOT NULL COMMENT 'Numeric stock ID (commas stripped)', name VARCHAR(255) NOT NULL COMMENT 'Full company / index name', symbol VARCHAR(10) NOT NULL COMMENT 'Ticker symbol e.g. AAPL', PRIMARY KEY (id_stock), UNIQUE KEY uq_symbol (symbol) ) ENGINE = InnoDB DEFAULT CHARSET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'Master list of stock identifiers';
-- ── Table: stock_prices ────────────────────────────────────────────────────── -- Daily OHLC price records. The close column drives all analytics. -- ──────────────────────────────────────────────────────────────────────────── CREATE TABLE IF NOT EXISTS stock_prices ( id INT NOT NULL AUTO_INCREMENT COMMENT 'Surrogate PK', id_stock BIGINT NOT NULL COMMENT 'FK → stock_identifiers', high DECIMAL(14, 4) NOT NULL COMMENT 'Intra-day high', low DECIMAL(14, 4) NOT NULL COMMENT 'Intra-day low', close DECIMAL(14, 4) NOT NULL COMMENT 'Closing price', price_date DATE NOT NULL COMMENT 'Trading date (YYYY-MM-DD)', PRIMARY KEY (id), UNIQUE KEY uq_stock_date (id_stock, price_date), CONSTRAINT fk_prices_stock FOREIGN KEY (id_stock) REFERENCES stock_identifiers (id_stock) ON DELETE CASCADE ) ENGINE = InnoDB DEFAULT CHARSET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'Daily high / low / close prices per stock';

package com.project;

import com.project.model.PerformanceRecord;
import com.project.model.StockPrice;
import com.project.service.*;
import com.project.util.FileUtils;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;

/**
 * Application entry point.
 *
 * <h2>Usage</h2>
 * <pre>
 *   java -jar stock-performance.jar &lt;stock_prices.csv&gt; [interval]
 * </pre>
 *
 * <ul>
 *   <li>{@code stock_prices.csv} — path to the prices file (relative or absolute)</li>
 *   <li>{@code interval}         — optional positive integer (trading days).
 *       <ul>
 *         <li>If omitted → produces <b>7day.csv</b>, <b>14day.csv</b>, <b>30day.csv</b></li>
 *         <li>If provided → produces <b>only</b> {@code <interval>day.csv}</li>
 *       </ul>
 *   </li>
 * </ul>
 *
 * <p>The identifiers file must be in the same directory as the prices file,
 * named {@code stock_identifiers.csv}.</p>
 *
 * <p>System.exit codes: 0 = success, 1 = bad arguments, 2 = IO / runtime error.</p>
 */
public class Main {

    private static final Logger log = LoggerFactory.getLogger(Main.class);

    /** Default intervals produced when no interval argument is supplied. */
    static final int[] DEFAULT_INTERVALS = {7, 14, 30};

    static final String IDENTIFIERS_FILE = "stock_identifiers.csv";

    public static void main(String[] args) {
        // ── 1.  Parse and validate arguments ────────────────────────────────
        // Interval argument is now OPTIONAL.
        if (args.length < 1) {
            System.err.println("Usage: java -jar stock-performance.jar <stock_prices.csv> [interval]");
            System.err.println("  No interval  → produces 7day.csv, 14day.csv, 30day.csv");
            System.err.println("  With interval → produces only <interval>day.csv");
            System.err.println("Example: java -jar stock-performance.jar files/stock_prices.csv 7");
            System.exit(1);
        }

        Path pricesPath = FileUtils.resolve(args[0]);

        // Parse optional interval
        Integer cliInterval = null;
        if (args.length >= 2) {
            try {
                cliInterval = Integer.parseInt(args[1]);
                if (cliInterval <= 0) throw new NumberFormatException("must be positive");
            } catch (NumberFormatException e) {
                System.err.println("Error: <interval> must be a positive integer, got: " + args[1]);
                System.exit(1);
            }
        }

        if (!Files.exists(pricesPath)) {
            System.err.println("Error: prices file not found: " + pricesPath);
            System.exit(1);
        }

        Path identifiersPath = pricesPath.resolveSibling(IDENTIFIERS_FILE);
        if (!Files.exists(identifiersPath)) {
            System.err.println("Error: identifiers file not found: " + identifiersPath);
            System.exit(1);
        }

        // ── 2.  Bootstrap services ───────────────────────────────────────────
        CsvReaderService      reader     = new CsvReaderService();
        PerformanceCalculator calculator = new PerformanceCalculator();
        CsvWriterService      writer     = new CsvWriterService();
        Path outputDir = FileUtils.resolve("output");

        try {
            // ── 3.  Read input data ──────────────────────────────────────────
            log.info("Reading input files …");
            log.info("  prices:      {}", pricesPath);
            log.info("  identifiers: {}", identifiersPath);
            List<StockPrice> prices = reader.read(identifiersPath, pricesPath);
            log.info("Loaded {} total price records across all symbols.", prices.size());

            // ── 4.  Determine intervals to process ───────────────────────────
            //   • No interval arg  → run all three defaults (7, 14, 30)
            //   • Interval provided → run only that one interval
            List<Integer> intervals = new ArrayList<>();
            if (cliInterval == null) {
                for (int i : DEFAULT_INTERVALS) intervals.add(i);
                log.info("No interval specified — producing 7day, 14day, 30day CSVs.");
            } else {
                intervals.add(cliInterval);
                log.info("Interval {} specified — producing only {}day.csv.", cliInterval, cliInterval);
            }

            // ── 5.  Calculate and write ──────────────────────────────────────
            List<Path> outputFiles = new ArrayList<>();

            for (int interval : intervals) {
                log.info("── Processing interval: {} trading days ──", interval);
                List<PerformanceRecord> records = calculator.calculate(prices, interval);
                Path outFile = CsvWriterService.outputPath(interval, outputDir);
                writer.write(records, outFile);
                outputFiles.add(outFile);
            }

            log.info("All output files written to: {}", outputDir.toAbsolutePath());

            // ── 6.  Send email (best-effort, opt-in) ────────────────────────
            String emailTo = System.getenv("EMAIL_TO");
            if (emailTo != null && !emailTo.isBlank()) {
                sendEmail(outputFiles);
            } else {
                log.info("EMAIL_TO not set — skipping email. Set EMAIL_TO=<address> to enable.");
            }

        } catch (Exception e) {
            log.error("Fatal error during processing: {}", e.getMessage(), e);
            System.exit(2);
        }

        log.info("Done.");
    }

    // ── private helpers ──────────────────────────────────────────────────────

    private static void sendEmail(List<Path> files) {
        try {
            EmailService.EmailConfig cfg = EmailService.EmailConfig.fromEnv();
            EmailService emailService = new EmailService(cfg);
            emailService.send(files);
        } catch (Throwable e) {
            // Email is best-effort: log the failure but do NOT abort the run.
            // We catch Throwable (not just Exception) to gracefully handle
            // NoClassDefFoundError when e.g. angus-mail is absent at runtime.
            log.warn("Email sending failed (non-fatal): {}", e.getMessage());
            log.debug("Email error detail:", e);
        }
    }
}

package com.project;

import com.project.config.DatabaseConfig;
import com.project.model.PerformanceRecord;
import com.project.model.StockPrice;
import com.project.repository.StockRepository;
import com.project.service.*;
import com.project.util.FileUtils;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.sql.DataSource;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;

/**
 * Application entry point — supports two modes:
 *
 * <h2>Mode 1: CSV (Part 1 – original behaviour)</h2>
 * <pre>
 *   java -jar stock-performance.jar &lt;stock_prices.csv&gt; [interval]
 * </pre>
 * Reads price CSVs, calculates N-day performance, writes Nday.csv, emails results.
 *
 * <h2>Mode 2: DB (Part 2 – database mode)</h2>
 * <pre>
 *   java -jar stock-performance.jar db
 * </pre>
 * Loads stock_identifiers.csv + stock_prices.csv into MySQL, computes monthly
 * average closing prices via SQL aggregation, writes monthly_average_prices.csv,
 * and emails the result.
 *
 * <p>System.exit codes: 0 = success, 1 = bad arguments, 2 = IO / runtime error.</p>
 */
public class Main {

    private static final Logger log = LoggerFactory.getLogger(Main.class);

    static final int[] DEFAULT_INTERVALS = {7, 14, 30};
    static final String IDENTIFIERS_FILE = "stock_identifiers.csv";

    public static void main(String[] args) {
        // ── Route to the correct mode ────────────────────────────────────────
        if (args.length >= 1 && "db".equalsIgnoreCase(args[0])) {
            runDatabaseMode();
        } else {
            runCsvMode(args);
        }
    }

    // ── Mode 2: Database ─────────────────────────────────────────────────────

    /**
     * Part 2 pipeline:
     * <ol>
     *   <li>Build a HikariCP DataSource from environment variables</li>
     *   <li>Load stock_identifiers.csv and stock_prices.csv into MySQL (idempotent)</li>
     *   <li>Query monthly average closing prices via SQL aggregation</li>
     *   <li>Write monthly_average_prices.csv to the output directory</li>
     *   <li>Email the CSV (best-effort)</li>
     * </ol>
     */
    private static void runDatabaseMode() {
        log.info("=== Stock Performance Calculator – Database Mode (Part 2) ===");
        try {
            DataSource       ds         = DatabaseConfig.createDataSource();
            StockRepository  repo       = new StockRepository(ds);
            DatabaseLoaderService loader = new DatabaseLoaderService(repo);
            MonthlyAverageService svc   = new MonthlyAverageService(repo, new MonthlyAverageCsvWriter());

            Path filesDir         = FileUtils.resolve("files");
            Path identifiersPath  = filesDir.resolve(IDENTIFIERS_FILE);
            Path pricesPath       = filesDir.resolve("stock_prices.csv");
            Path outputDir        = FileUtils.resolve("output");

            // Step 1: Load CSV data into MySQL (skipped if tables already have data)
            loader.load(identifiersPath, pricesPath);

            // Step 2: Compute monthly averages + write CSV + email
            Path csvFile = svc.generateAndSend(outputDir);
            log.info("Generated: {}", csvFile.toAbsolutePath());

            log.info("=== Database Mode Complete ===");

        } catch (Exception e) {
            log.error("Fatal error in database mode: {}", e.getMessage(), e);
            System.exit(2);
        }
    }

    // ── Mode 1: CSV (original Part 1 behaviour) ───────────────────────────────

    private static void runCsvMode(String[] args) {
        log.info("=== Stock Performance Calculator – CSV Mode (Part 1) ===");

        if (args.length < 1) {
            System.err.println("Usage: java -jar stock-performance.jar <stock_prices.csv> [interval]");
            System.err.println("       java -jar stock-performance.jar db                  (Part 2 DB mode)");
            System.exit(1);
        }

        Path pricesPath = FileUtils.resolve(args[0]);

        Integer cliInterval = null;
        if (args.length >= 2) {
            try {
                cliInterval = Integer.parseInt(args[1]);
                if (cliInterval <= 0) throw new NumberFormatException("must be positive");
            } catch (NumberFormatException e) {
                System.err.println("Error: <interval> must be a positive integer, got: " + args[1]);
                System.exit(1);
            }
        }

        if (!Files.exists(pricesPath)) {
            System.err.println("Error: prices file not found: " + pricesPath);
            System.exit(1);
        }

        Path identifiersPath = pricesPath.resolveSibling(IDENTIFIERS_FILE);
        if (!Files.exists(identifiersPath)) {
            System.err.println("Error: identifiers file not found: " + identifiersPath);
            System.exit(1);
        }

        CsvReaderService      reader     = new CsvReaderService();
        PerformanceCalculator calculator = new PerformanceCalculator();
        CsvWriterService      writer     = new CsvWriterService();
        Path outputDir = FileUtils.resolve("output");

        try {
            log.info("Reading input files …");
            List<StockPrice> prices = reader.read(identifiersPath, pricesPath);
            log.info("Loaded {} total price records across all symbols.", prices.size());

            List<Integer> intervals = new ArrayList<>();
            if (cliInterval == null) {
                for (int i : DEFAULT_INTERVALS) intervals.add(i);
                log.info("No interval specified — producing 7day, 14day, 30day CSVs.");
            } else {
                intervals.add(cliInterval);
                log.info("Interval {} specified — producing only {}day.csv.", cliInterval, cliInterval);
            }

            List<Path> outputFiles = new ArrayList<>();
            for (int interval : intervals) {
                log.info("── Processing interval: {} trading days ──", interval);
                List<PerformanceRecord> records = calculator.calculate(prices, interval);
                Path outFile = CsvWriterService.outputPath(interval, outputDir);
                writer.write(records, outFile);
                outputFiles.add(outFile);
            }

            log.info("All output files written to: {}", outputDir.toAbsolutePath());

            String emailTo = System.getenv("EMAIL_TO");
            if (emailTo != null && !emailTo.isBlank()) {
                sendEmail(outputFiles);
            } else {
                log.info("EMAIL_TO not set — skipping email.");
            }

        } catch (Exception e) {
            log.error("Fatal error during processing: {}", e.getMessage(), e);
            System.exit(2);
        }

        log.info("Done.");
    }

    private static void sendEmail(List<Path> files) {
        try {
            EmailService.EmailConfig cfg = EmailService.EmailConfig.fromEnv();
            EmailService emailService = new EmailService(cfg);
            emailService.send(files);
        } catch (Throwable e) {
            log.warn("Email sending failed (non-fatal): {}", e.getMessage());
            log.debug("Email error detail:", e);
        }
    }
}

package com.project.config;

import com.zaxxer.hikari.HikariConfig;
import com.zaxxer.hikari.HikariDataSource;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.sql.DataSource;

/**
 * Factory for the application's JDBC {@link DataSource} backed by HikariCP.
 *
 * <h2>Why HikariCP?</h2>
 * HikariCP is the fastest, most battle-tested connection pool on the JVM.
 * It is already the default in Spring Boot and is a natural fit for any
 * Java application that talks to a relational database.
 *
 * <h2>Configuration</h2>
 * Every parameter is read from environment variables with sensible defaults,
 * so the same fat-jar works:
 * <ul>
 *   <li>Locally → pointing at {@code localhost:3306}</li>
 *   <li>Inside Docker Compose → pointing at the {@code mysql} service</li>
 * </ul>
 *
 * <h2>Notable JDBC URL options</h2>
 * <ul>
 *   <li>{@code useSSL=false} – no SSL needed for a local/compose deployment</li>
 *   <li>{@code allowPublicKeyRetrieval=true} – required by MySQL 8 caching_sha2_password</li>
 *   <li>{@code rewriteBatchedStatements=true} – converts individual batch INSERTs
 *       into a single multi-row statement, dramatically speeding up the CSV bulk-load</li>
 *   <li>{@code serverTimezone=UTC} – avoids ambiguous DST conversions</li>
 * </ul>
 */
public final class DatabaseConfig {

    private static final Logger log = LoggerFactory.getLogger(DatabaseConfig.class);

    private DatabaseConfig() { /* utility class – no instances */ }

    /**
     * Creates and returns a configured {@link HikariDataSource}.
     *
     * <p>The pool is sized for a batch-job workload (max 5 connections).
     * Callers are responsible for closing the returned DataSource when done.</p>
     */
    public static DataSource createDataSource() {
        String host     = env("DB_HOST",     "localhost");
        String port     = env("DB_PORT",     "3306");
        String dbName   = env("DB_NAME",     "stockdb");
        String user     = env("DB_USER",     "stockuser");
        String password = env("DB_PASSWORD", "stockpass");

        String url = "jdbc:mysql://%s:%s/%s?useSSL=false&allowPublicKeyRetrieval=true&serverTimezone=UTC&rewriteBatchedStatements=true&characterEncoding=UTF-8"
                .formatted(host, port, dbName);

        log.info("Configuring HikariCP → jdbc:mysql://{}:{}/{}", host, port, dbName);

        HikariConfig cfg = new HikariConfig();
        cfg.setJdbcUrl(url);
        cfg.setUsername(user);
        cfg.setPassword(password);
        cfg.setDriverClassName("com.mysql.cj.jdbc.Driver");

        // Pool sizing: batch job, not a web server → small pool is fine.
        cfg.setMaximumPoolSize(5);
        cfg.setMinimumIdle(1);
        cfg.setConnectionTimeout(30_000L);   // 30 s
        cfg.setIdleTimeout(600_000L);        // 10 min
        cfg.setMaxLifetime(1_800_000L);      // 30 min
        cfg.setPoolName("StockPool");

        // Validate connections before use; detects stale connections after MySQL restart.
        cfg.setConnectionTestQuery("SELECT 1");

        return new HikariDataSource(cfg);
    }

    // ── helpers ───────────────────────────────────────────────────────────────

    private static String env(String key, String defaultVal) {
        String v = System.getenv(key);
        return (v != null && !v.isBlank()) ? v.trim() : defaultVal;
    }
}

package com.project.model;

import java.math.BigDecimal;
import java.util.Objects;

/**
 * Immutable value object representing the average monthly closing price
 * for one stock symbol.
 *
 * <p>Output CSV format: {@code symbol,month,average_price}
 * e.g. {@code AAPL,JAN,184.52}</p>
 *
 * <p>Uses Java 16+ {@code record} because all fields are simple and the
 * compact constructor provides the only validation needed.</p>
 */
public record MonthlyAverage(String symbol, String month, BigDecimal averagePrice) {

    /** Compact canonical constructor – validates required fields. */
    public MonthlyAverage {
        Objects.requireNonNull(symbol,       "symbol must not be null");
        Objects.requireNonNull(month,        "month must not be null");
        Objects.requireNonNull(averagePrice, "averagePrice must not be null");
        if (symbol.isBlank())
            throw new IllegalArgumentException("symbol must not be blank");
        if (month.isBlank())
            throw new IllegalArgumentException("month must not be blank");
    }
}

package com.project.repository;

import com.project.model.MonthlyAverage;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.sql.DataSource;
import java.math.BigDecimal;
import java.sql.*;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.Objects;

/**
 * JDBC repository for all stock-data database interactions.
 *
 * <h2>Design decisions</h2>
 * <ul>
 *   <li><b>Pure JDBC</b> – no ORM; minimal overhead, direct SQL control.</li>
 *   <li><b>INSERT IGNORE</b> – idempotent bulk inserts; re-running the app never
 *       creates duplicate rows (the UNIQUE key on stock_prices enforces this at
 *       the DB level too).</li>
 *   <li><b>Batch inserts</b> – rows are sent to MySQL in batches of
 *       {@value #BATCH_SIZE}. Combined with the {@code rewriteBatchedStatements}
 *       JDBC URL flag, this turns ~1300 individual INSERTs into a handful of
 *       multi-row statements, dramatically reducing round-trips.</li>
 *   <li><b>SQL aggregation for monthly averages</b> – pushing GROUP BY + AVG to
 *       the database engine is faster and more correct than doing it in Java
 *       loops. It also makes the query visible and auditable.</li>
 *   <li><b>Explicit transactions</b> – autoCommit is disabled during bulk loads;
 *       a rollback happens if any batch fails.</li>
 * </ul>
 */
public class StockRepository {

    private static final Logger log = LoggerFactory.getLogger(StockRepository.class);

    /** Number of rows per JDBC batch flush. */
    static final int BATCH_SIZE = 500;

    /**
     * Monthly-average SQL.
     *
     * <p>Groups by (symbol, year, month) so that partial months at the start
     * and end of the dataset produce their own rows. {@code UPPER(DATE_FORMAT(…,'%b'))}
     * converts MySQL's abbreviated month name ('Jan') to the required 'JAN' format.</p>
     *
     * <p>Ordering: symbol A→Z, then chronological year/month.</p>
     */
    static final String SQL_MONTHLY_AVG = """
            SELECT
                si.symbol,
                UPPER(DATE_FORMAT(sp.price_date, '%b')) AS month,
                ROUND(AVG(sp.close), 2)                 AS average_price
            FROM  stock_prices sp
            INNER JOIN stock_identifiers si ON sp.id_stock = si.id_stock
            GROUP BY
                si.symbol,
                YEAR(sp.price_date),
                MONTH(sp.price_date)
            ORDER BY
                si.symbol           ASC,
                YEAR(sp.price_date) ASC,
                MONTH(sp.price_date) ASC
            """;

    // ── nested row holders ────────────────────────────────────────────────────

    /** Raw data for one row of the {@code stock_identifiers} table. */
    public record IdentifierRow(long idStock, String name, String symbol) {}

    /** Raw data for one row of the {@code stock_prices} table. */
    public record PriceRow(long idStock,
                           BigDecimal high,
                           BigDecimal low,
                           BigDecimal close,
                           LocalDate date) {}

    // ── fields ────────────────────────────────────────────────────────────────

    private final DataSource dataSource;

    public StockRepository(DataSource dataSource) {
        this.dataSource = Objects.requireNonNull(dataSource, "dataSource must not be null");
    }

    // ── existence checks ──────────────────────────────────────────────────────

    /** @return {@code true} if {@code stock_identifiers} contains at least one row */
    public boolean hasIdentifiers() throws SQLException {
        return countRows("stock_identifiers") > 0;
    }

    /** @return {@code true} if {@code stock_prices} contains at least one row */
    public boolean hasPrices() throws SQLException {
        return countRows("stock_prices") > 0;
    }

    private long countRows(String table) throws SQLException {
        // table name is a constant – no SQL-injection risk.
        try (Connection conn = dataSource.getConnection();
             PreparedStatement ps = conn.prepareStatement("SELECT COUNT(*) FROM " + table);
             ResultSet rs = ps.executeQuery()) {
            rs.next();
            return rs.getLong(1);
        }
    }

    // ── bulk inserts ──────────────────────────────────────────────────────────

    /**
     * Inserts stock identifiers using {@code INSERT IGNORE} (idempotent).
     *
     * @param rows list of identifier rows to insert
     * @return number of rows actually inserted (duplicates are skipped)
     * @throws SQLException on any database error; the transaction is rolled back
     */
    public int insertIdentifiers(List<IdentifierRow> rows) throws SQLException {
        if (rows == null || rows.isEmpty()) return 0;

        final String sql =
                "INSERT IGNORE INTO stock_identifiers (id_stock, name, symbol) VALUES (?,?,?)";
        int total = 0;

        try (Connection conn = dataSource.getConnection()) {
            conn.setAutoCommit(false);
            try (PreparedStatement ps = conn.prepareStatement(sql)) {
                int batchCount = 0;
                for (IdentifierRow r : rows) {
                    ps.setLong(1,   r.idStock());
                    ps.setString(2, r.name());
                    ps.setString(3, r.symbol());
                    ps.addBatch();
                    if (++batchCount % BATCH_SIZE == 0) {
                        total += sumBatch(ps.executeBatch());
                        log.debug("Flushed identifier batch; running total={}", total);
                    }
                }
                total += sumBatch(ps.executeBatch()); // flush remainder
                conn.commit();
            } catch (SQLException ex) {
                conn.rollback();
                throw ex;
            } finally {
                conn.setAutoCommit(true);
            }
        }
        return total;
    }

    /**
     * Inserts daily price rows using {@code INSERT IGNORE} (idempotent).
     *
     * @param rows list of price rows to insert
     * @return number of rows actually inserted (duplicates are skipped)
     * @throws SQLException on any database error; the transaction is rolled back
     */
    public int insertPrices(List<PriceRow> rows) throws SQLException {
        if (rows == null || rows.isEmpty()) return 0;

        final String sql =
                "INSERT IGNORE INTO stock_prices (id_stock, high, low, close, price_date)" +
                " VALUES (?,?,?,?,?)";
        int total = 0;

        try (Connection conn = dataSource.getConnection()) {
            conn.setAutoCommit(false);
            try (PreparedStatement ps = conn.prepareStatement(sql)) {
                int batchCount = 0;
                for (PriceRow r : rows) {
                    ps.setLong(1,       r.idStock());
                    ps.setBigDecimal(2, r.high());
                    ps.setBigDecimal(3, r.low());
                    ps.setBigDecimal(4, r.close());
                    ps.setDate(5,       Date.valueOf(r.date()));
                    ps.addBatch();
                    if (++batchCount % BATCH_SIZE == 0) {
                        total += sumBatch(ps.executeBatch());
                        log.debug("Flushed price batch; running total={}", total);
                    }
                }
                total += sumBatch(ps.executeBatch()); // flush remainder
                conn.commit();
            } catch (SQLException ex) {
                conn.rollback();
                throw ex;
            } finally {
                conn.setAutoCommit(true);
            }
        }
        return total;
    }

    // ── queries ───────────────────────────────────────────────────────────────

    /**
     * Executes the monthly-average SQL query and returns the results.
     *
     * <p>All aggregation is performed in the database (GROUP BY + AVG + ROUND).
     * No Java-side summation or grouping is needed.</p>
     *
     * @return list of monthly averages ordered by symbol then chronological month
     * @throws SQLException on any database error
     */
    public List<MonthlyAverage> getMonthlyAverages() throws SQLException {
        List<MonthlyAverage> results = new ArrayList<>();
        try (Connection conn = dataSource.getConnection();
             PreparedStatement ps = conn.prepareStatement(SQL_MONTHLY_AVG);
             ResultSet rs = ps.executeQuery()) {
            while (rs.next()) {
                results.add(new MonthlyAverage(
                        rs.getString("symbol"),
                        rs.getString("month"),
                        rs.getBigDecimal("average_price")));
            }
        }
        log.info("Monthly-average query returned {} rows.", results.size());
        return results;
    }

    // ── private helpers ───────────────────────────────────────────────────────

    /**
     * Sums the update counts returned by {@link PreparedStatement#executeBatch()}.
     * Handles {@link Statement#SUCCESS_NO_INFO} (-2) which MySQL may return
     * when {@code rewriteBatchedStatements=true} is active.
     */
    private static int sumBatch(int[] counts) {
        int n = 0;
        for (int c : counts) {
            if (c > 0) n += c;
            else if (c == Statement.SUCCESS_NO_INFO) n++;
            // Statement.EXECUTE_FAILED (-3) is intentionally ignored –
            // INSERT IGNORE means failures are expected for duplicates.
        }
        return n;
    }
}

package com.project.service;

import com.project.repository.StockRepository;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.apache.commons.csv.CSVRecord;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.Reader;
import java.math.BigDecimal;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.sql.SQLException;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;
import java.util.Objects;

/**
 * Reads the stock CSV files and loads their contents into the MySQL database.
 *
 * <h2>Why Java-based loading instead of LOAD DATA INFILE?</h2>
 * <ul>
 *   <li>The {@code id_stock} column uses quoted values with embedded thousand-
 *       separator commas (e.g. {@code "40,359,100"}) that must be normalised to
 *       {@code 40359100} before insertion.  MySQL's {@code LOAD DATA INFILE}
 *       cannot perform this transformation without complex {@code @var} tricks.</li>
 *   <li>Price columns also use quoted comma-formatted numbers in some rows
 *       (e.g. {@code "6,894.87"}).</li>
 *   <li>MySQL's {@code secure_file_priv} requires extra Docker configuration to
 *       allow file access inside the container.</li>
 *   <li>Reusing Apache Commons CSV (already on the classpath) keeps the parsing
 *       logic consistent, tested, and portable.</li>
 * </ul>
 *
 * <h2>Idempotency</h2>
 * Before inserting, the loader checks whether each table already contains data.
 * Running {@code docker compose up} multiple times therefore produces no
 * duplicates.  The underlying {@code INSERT IGNORE} provides a second line of
 * defence at the database level.
 */
public class DatabaseLoaderService {

    private static final Logger log = LoggerFactory.getLogger(DatabaseLoaderService.class);

    private static final DateTimeFormatter DATE_FMT = DateTimeFormatter.ISO_LOCAL_DATE;

    /** Shared CSV format matching both input files (RFC-4180, first row = header). */
    private static final CSVFormat CSV_FORMAT = CSVFormat.DEFAULT.builder()
            .setHeader()
            .setSkipHeaderRecord(true)
            .setIgnoreSurroundingSpaces(true)
            .setTrim(true)
            .build();

    private final StockRepository repository;

    public DatabaseLoaderService(StockRepository repository) {
        this.repository = Objects.requireNonNull(repository, "repository must not be null");
    }

    // ── public API ────────────────────────────────────────────────────────────

    /**
     * Loads both CSV files into the database.
     * Identifiers are loaded first (required by the FK constraint on prices).
     * Each table is skipped if it already contains data.
     *
     * @param identifiersPath path to {@code stock_identifiers.csv}
     * @param pricesPath      path to {@code stock_prices.csv}
     * @throws Exception if a CSV parse or database error occurs
     */
    public void load(Path identifiersPath, Path pricesPath) throws Exception {
        log.info("=== CSV → Database Load ===");

        // ── stock_identifiers ─────────────────────────────────────────────────
        if (repository.hasIdentifiers()) {
            log.info("stock_identifiers already populated – skipping.");
        } else {
            List<StockRepository.IdentifierRow> ids = parseIdentifiers(identifiersPath);
            int inserted = repository.insertIdentifiers(ids);
            log.info("Loaded {} identifier rows into stock_identifiers ({} parsed).",
                     inserted, ids.size());
        }

        // ── stock_prices ──────────────────────────────────────────────────────
        if (repository.hasPrices()) {
            log.info("stock_prices already populated – skipping.");
        } else {
            List<StockRepository.PriceRow> prices = parsePrices(pricesPath);
            int inserted = repository.insertPrices(prices);
            log.info("Loaded {} price rows into stock_prices ({} parsed).",
                     inserted, prices.size());
        }

        log.info("=== Load Complete ===");
    }

    // ── CSV parsers (package-visible for unit testing) ─────────────────────

    /**
     * Parses {@code stock_identifiers.csv} and returns a list of
     * {@link StockRepository.IdentifierRow} objects ready for batch insert.
     */
    List<StockRepository.IdentifierRow> parseIdentifiers(Path path) throws Exception {
        List<StockRepository.IdentifierRow> list = new ArrayList<>();
        int skipped = 0;

        try (Reader reader = Files.newBufferedReader(path, StandardCharsets.UTF_8);
             CSVParser parser = CSV_FORMAT.parse(reader)) {

            for (CSVRecord row : parser) {
                try {
                    long   idStock = normaliseId(row.get("id_stock"));
                    String name    = row.get("name").trim();
                    String symbol  = row.get("symbol").trim().toUpperCase();

                    if (name.isEmpty() || symbol.isEmpty()) {
                        log.warn("Skipping incomplete identifier row #{}", row.getRecordNumber());
                        skipped++;
                        continue;
                    }
                    list.add(new StockRepository.IdentifierRow(idStock, name, symbol));

                } catch (Exception e) {
                    log.warn("Skipping malformed identifier row #{}: {}",
                             row.getRecordNumber(), e.getMessage());
                    skipped++;
                }
            }
        }

        log.info("Parsed {} identifier rows, {} skipped from {}",
                 list.size(), skipped, path.getFileName());
        return list;
    }

    /**
     * Parses {@code stock_prices.csv} and returns a list of
     * {@link StockRepository.PriceRow} objects ready for batch insert.
     * All columns (high, low, close) are retained – unlike {@link CsvReaderService}
     * which only keeps the close price.
     */
    List<StockRepository.PriceRow> parsePrices(Path path) throws Exception {
        List<StockRepository.PriceRow> list = new ArrayList<>(1400);
        int skipped = 0;

        try (Reader reader = Files.newBufferedReader(path, StandardCharsets.UTF_8);
             CSVParser parser = CSV_FORMAT.parse(reader)) {

            for (CSVRecord row : parser) {
                try {
                    long       idStock = normaliseId(row.get("id_stock"));
                    BigDecimal high    = parseDecimal(row.get("high"),  row.getRecordNumber());
                    BigDecimal low     = parseDecimal(row.get("low"),   row.getRecordNumber());
                    BigDecimal close   = parseDecimal(row.get("close"), row.getRecordNumber());
                    LocalDate  date    = LocalDate.parse(row.get("date").trim(), DATE_FMT);

                    list.add(new StockRepository.PriceRow(idStock, high, low, close, date));

                } catch (Exception e) {
                    log.warn("Skipping malformed price row #{}: {}",
                             row.getRecordNumber(), e.getMessage());
                    skipped++;
                }
            }
        }

        log.info("Parsed {} price rows, {} skipped from {}",
                 list.size(), skipped, path.getFileName());
        return list;
    }

    // ── value helpers (package-visible for unit testing) ──────────────────────

    /**
     * Strips thousand-separator commas and trims whitespace, then parses as long.
     * E.g. {@code "40,359,100"} → {@code 40359100L}.
     */
    static long normaliseId(String raw) {
        return Long.parseLong(raw.replace(",", "").trim());
    }

    /**
     * Strips thousand-separator commas and trims whitespace, then parses as
     * {@link BigDecimal}.  E.g. {@code "6,894.87"} → {@code BigDecimal("6894.87")}.
     */
    private static BigDecimal parseDecimal(String raw, long rowNum) {
        try {
            return new BigDecimal(raw.trim().replace(",", ""));
        } catch (NumberFormatException e) {
            throw new IllegalArgumentException(
                    "Cannot parse decimal '%s' at row %d".formatted(raw, rowNum), e);
        }
    }
}

package com.project.service;

import com.project.model.MonthlyAverage;
import com.project.util.FileUtils;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.BufferedWriter;
import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;
import java.util.Objects;

/**
 * Writes a list of {@link MonthlyAverage} objects to a CSV file.
 *
 * <h2>Output format</h2>
 * <pre>
 *   symbol,month,average_price
 *   AAPL,JAN,222.77
 *   AAPL,FEB,229.61
 *   …
 * </pre>
 *
 * <h2>Design decisions</h2>
 * <ul>
 *   <li>Apache Commons CSV is used for correct RFC-4180 quoting/escaping,
 *       consistent with the rest of the project.</li>
 *   <li>Parent directories are created automatically.</li>
 *   <li>UTF-8 without BOM – universally readable in spreadsheets and scripts.</li>
 * </ul>
 */
public class MonthlyAverageCsvWriter {

    private static final Logger log = LoggerFactory.getLogger(MonthlyAverageCsvWriter.class);

    /** Column headers matching the required output specification. */
    static final String[] HEADERS = {"symbol", "month", "average_price"};

    private static final CSVFormat CSV_FORMAT = CSVFormat.DEFAULT.builder()
            .setHeader(HEADERS)
            .build();

    /**
     * Writes {@code averages} to {@code outputPath}.
     * Existing files are silently overwritten.
     *
     * @param averages   list of monthly averages to write (must not be null)
     * @param outputPath destination file path (must not be null)
     * @throws IOException if writing fails
     */
    public void write(List<MonthlyAverage> averages, Path outputPath) throws IOException {
        Objects.requireNonNull(averages,    "averages must not be null");
        Objects.requireNonNull(outputPath, "outputPath must not be null");

        FileUtils.ensureParentExists(outputPath);

        log.info("Writing {} monthly-average rows to {}",
                 averages.size(), outputPath.toAbsolutePath());

        try (BufferedWriter bw      = Files.newBufferedWriter(outputPath, StandardCharsets.UTF_8);
             CSVPrinter     printer = new CSVPrinter(bw, CSV_FORMAT)) {

            for (MonthlyAverage ma : averages) {
                printer.printRecord(
                        ma.symbol(),
                        ma.month(),
                        ma.averagePrice().toPlainString()
                );
            }
        }

        log.info("Successfully wrote {}", outputPath.getFileName());
    }
}

package com.project.repository;

import com.project.model.MonthlyAverage;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.mockito.junit.jupiter.MockitoSettings;
import org.mockito.quality.Strictness;

import javax.sql.DataSource;
import java.math.BigDecimal;
import java.sql.*;
import java.time.LocalDate;
import java.util.List;

import static org.assertj.core.api.Assertions.*;
import static org.mockito.ArgumentMatchers.*;
import static org.mockito.Mockito.*;

/**
 * Unit tests for {@link StockRepository}.
 *
 * <p>All JDBC objects (DataSource, Connection, PreparedStatement, ResultSet) are
 * mocked with Mockito so no real database is required. This keeps tests fast,
 * deterministic, and runnable in any CI environment.</p>
 */
@ExtendWith(MockitoExtension.class)
@MockitoSettings(strictness = Strictness.LENIENT)
@DisplayName("StockRepository")
class StockRepositoryTest {

    @Mock DataSource        dataSource;
    @Mock Connection        connection;
    @Mock PreparedStatement preparedStatement;
    @Mock ResultSet         resultSet;

    private StockRepository repo;

    @BeforeEach
    void setUp() throws Exception {
        repo = new StockRepository(dataSource);
        when(dataSource.getConnection()).thenReturn(connection);
    }

    // ── constructor ───────────────────────────────────────────────────────────

    @Test
    @DisplayName("constructor rejects null DataSource")
    void constructor_rejectsNull() {
        assertThatNullPointerException()
                .isThrownBy(() -> new StockRepository(null))
                .withMessageContaining("dataSource");
    }

    // ── hasIdentifiers ────────────────────────────────────────────────────────

    @Test
    @DisplayName("hasIdentifiers returns true when count > 0")
    void hasIdentifiers_trueWhenRowsExist() throws Exception {
        when(connection.prepareStatement(anyString())).thenReturn(preparedStatement);
        when(preparedStatement.executeQuery()).thenReturn(resultSet);
        when(resultSet.next()).thenReturn(true);
        when(resultSet.getLong(1)).thenReturn(5L);

        assertThat(repo.hasIdentifiers()).isTrue();
    }

    @Test
    @DisplayName("hasIdentifiers returns false when count == 0")
    void hasIdentifiers_falseWhenEmpty() throws Exception {
        when(connection.prepareStatement(anyString())).thenReturn(preparedStatement);
        when(preparedStatement.executeQuery()).thenReturn(resultSet);
        when(resultSet.next()).thenReturn(true);
        when(resultSet.getLong(1)).thenReturn(0L);

        assertThat(repo.hasIdentifiers()).isFalse();
    }

    // ── insertIdentifiers ─────────────────────────────────────────────────────

    @Test
    @DisplayName("insertIdentifiers returns 0 for an empty list without touching the DB")
    void insertIdentifiers_emptyList_returnsZero() throws Exception {
        int result = repo.insertIdentifiers(List.of());
        assertThat(result).isZero();
        verifyNoInteractions(dataSource); // no DB call made
    }

    @Test
    @DisplayName("insertIdentifiers commits and returns batch total")
    void insertIdentifiers_insertsAndCommits() throws Exception {
        List<StockRepository.IdentifierRow> rows = List.of(
                new StockRepository.IdentifierRow(13L, "Apple Inc.", "AAPL"),
                new StockRepository.IdentifierRow(5094L, "Microsoft Corporation", "MSFT")
        );

        when(connection.prepareStatement(anyString())).thenReturn(preparedStatement);
        when(preparedStatement.executeBatch()).thenReturn(new int[]{1, 1});

        int result = repo.insertIdentifiers(rows);

        assertThat(result).isEqualTo(2);
        verify(connection).setAutoCommit(false);
        verify(connection).commit();
        verify(connection).setAutoCommit(true);
    }

    // ── insertPrices ──────────────────────────────────────────────────────────

    @Test
    @DisplayName("insertPrices returns 0 for an empty list without touching the DB")
    void insertPrices_emptyList_returnsZero() throws Exception {
        int result = repo.insertPrices(List.of());
        assertThat(result).isZero();
        verifyNoInteractions(dataSource);
    }

    @Test
    @DisplayName("insertPrices commits with SUCCESS_NO_INFO counted as 1 row")
    void insertPrices_successNoInfo_countedAsOne() throws Exception {
        List<StockRepository.PriceRow> rows = List.of(
                new StockRepository.PriceRow(13L,
                        new BigDecimal("230.00"),
                        new BigDecimal("220.00"),
                        new BigDecimal("225.00"),
                        LocalDate.of(2025, 1, 20))
        );

        when(connection.prepareStatement(anyString())).thenReturn(preparedStatement);
        // MySQL with rewriteBatchedStatements returns SUCCESS_NO_INFO (-2)
        when(preparedStatement.executeBatch())
                .thenReturn(new int[]{Statement.SUCCESS_NO_INFO});

        int result = repo.insertPrices(rows);

        assertThat(result).isEqualTo(1);
        verify(connection).commit();
    }

    // ── getMonthlyAverages ────────────────────────────────────────────────────

    @Test
    @DisplayName("getMonthlyAverages returns empty list when ResultSet is empty")
    void getMonthlyAverages_emptyResultSet() throws Exception {
        when(connection.prepareStatement(anyString())).thenReturn(preparedStatement);
        when(preparedStatement.executeQuery()).thenReturn(resultSet);
        when(resultSet.next()).thenReturn(false); // no rows

        List<MonthlyAverage> result = repo.getMonthlyAverages();
        assertThat(result).isEmpty();
    }

    @Test
    @DisplayName("getMonthlyAverages maps ResultSet rows to MonthlyAverage objects")
    void getMonthlyAverages_mapsRows() throws Exception {
        when(connection.prepareStatement(anyString())).thenReturn(preparedStatement);
        when(preparedStatement.executeQuery()).thenReturn(resultSet);
        // Simulate two result rows, then EOF
        when(resultSet.next()).thenReturn(true, true, false);
        when(resultSet.getString("symbol")).thenReturn("AAPL", "GOOG");
        when(resultSet.getString("month")).thenReturn("JAN", "JAN");
        when(resultSet.getBigDecimal("average_price"))
                .thenReturn(new BigDecimal("222.77"), new BigDecimal("185.34"));

        List<MonthlyAverage> result = repo.getMonthlyAverages();

        assertThat(result).hasSize(2);
        assertThat(result.get(0).symbol()).isEqualTo("AAPL");
        assertThat(result.get(0).month()).isEqualTo("JAN");
        assertThat(result.get(0).averagePrice()).isEqualByComparingTo("222.77");
        assertThat(result.get(1).symbol()).isEqualTo("GOOG");
    }

    // ── SQL_MONTHLY_AVG constant ──────────────────────────────────────────────

    @Test
    @DisplayName("SQL_MONTHLY_AVG contains required SQL keywords")
    void sqlMonthlyAvg_containsExpectedKeywords() {
        String sql = StockRepository.SQL_MONTHLY_AVG.toLowerCase();
        assertThat(sql).contains("avg(");
        assertThat(sql).contains("group by");
        assertThat(sql).contains("order by");
        assertThat(sql).contains("inner join");
        assertThat(sql).contains("upper(date_format(");
    }
}

package com.project.service;

import com.project.repository.StockRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.junit.jupiter.api.io.TempDir;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.math.BigDecimal;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;

import static org.assertj.core.api.Assertions.*;
import static org.mockito.Mockito.*;

/**
 * Unit tests for {@link DatabaseLoaderService}.
 *
 * <p>CSV parsing helpers ({@code parseIdentifiers}, {@code parsePrices},
 * {@code normaliseId}) are exercised using inline CSV fixtures written to a
 * {@code @TempDir}.  The {@link StockRepository} is mocked so no database
 * is required.</p>
 */
@ExtendWith(MockitoExtension.class)
@DisplayName("DatabaseLoaderService")
class DatabaseLoaderServiceTest {

    @Mock StockRepository repository;

    private DatabaseLoaderService service;

    @BeforeEach
    void setUp() {
        service = new DatabaseLoaderService(repository);
    }

    // ── normaliseId ───────────────────────────────────────────────────────────

    @Test
    @DisplayName("normaliseId strips commas from quoted CSV id (\"40,359,100\" → 40359100)")
    void normaliseId_stripsCommas() {
        assertThat(DatabaseLoaderService.normaliseId("40,359,100")).isEqualTo(40359100L);
        assertThat(DatabaseLoaderService.normaliseId("7,458")).isEqualTo(7458L);
        assertThat(DatabaseLoaderService.normaliseId("13")).isEqualTo(13L);
    }

    @Test
    @DisplayName("normaliseId trims surrounding whitespace")
    void normaliseId_trimsWhitespace() {
        assertThat(DatabaseLoaderService.normaliseId("  5,094  ")).isEqualTo(5094L);
    }

    // ── parseIdentifiers ──────────────────────────────────────────────────────

    @Test
    @DisplayName("parseIdentifiers correctly maps all rows from a valid CSV")
    void parseIdentifiers_parsesAllRows(@TempDir Path tmp) throws Exception {
        Path csv = tmp.resolve("stock_identifiers.csv");
        Files.writeString(csv, """
                "id_stock","name","symbol"
                "13","Apple Inc.","AAPL"
                "40,359,100","Alphabet Inc.","GOOG"
                "5,094","Microsoft Corporation","MSFT"
                """, StandardCharsets.UTF_8);

        List<StockRepository.IdentifierRow> rows = service.parseIdentifiers(csv);

        assertThat(rows).hasSize(3);
        assertThat(rows.get(0).idStock()).isEqualTo(13L);
        assertThat(rows.get(0).symbol()).isEqualTo("AAPL");
        assertThat(rows.get(1).idStock()).isEqualTo(40359100L);
        assertThat(rows.get(1).symbol()).isEqualTo("GOOG");
        assertThat(rows.get(2).idStock()).isEqualTo(5094L);
    }

    @Test
    @DisplayName("parseIdentifiers upcases symbol")
    void parseIdentifiers_upcasesSymbol(@TempDir Path tmp) throws Exception {
        Path csv = tmp.resolve("ids.csv");
        Files.writeString(csv, """
                "id_stock","name","symbol"
                "13","Apple Inc.","aapl"
                """, StandardCharsets.UTF_8);

        List<StockRepository.IdentifierRow> rows = service.parseIdentifiers(csv);
        assertThat(rows.get(0).symbol()).isEqualTo("AAPL");
    }

    @Test
    @DisplayName("parseIdentifiers skips rows with blank symbol")
    void parseIdentifiers_skipsBlankSymbol(@TempDir Path tmp) throws Exception {
        Path csv = tmp.resolve("ids.csv");
        Files.writeString(csv, """
                "id_stock","name","symbol"
                "99","Unknown","   "
                "13","Apple Inc.","AAPL"
                """, StandardCharsets.UTF_8);

        List<StockRepository.IdentifierRow> rows = service.parseIdentifiers(csv);
        assertThat(rows).hasSize(1);
        assertThat(rows.get(0).symbol()).isEqualTo("AAPL");
    }

    // ── parsePrices ───────────────────────────────────────────────────────────

    @Test
    @DisplayName("parsePrices parses all OHLC columns correctly")
    void parsePrices_parsesAllColumns(@TempDir Path tmp) throws Exception {
        Path csv = tmp.resolve("stock_prices.csv");
        Files.writeString(csv, """
                "id_stock","high","low","close","date"
                "13","229.98","219.38","222.64","2025-01-21"
                "7,458","6,894.87","6,824.31","6,858.47","2026-01-02"
                """, StandardCharsets.UTF_8);

        List<StockRepository.PriceRow> rows = service.parsePrices(csv);

        assertThat(rows).hasSize(2);

        StockRepository.PriceRow first = rows.get(0);
        assertThat(first.idStock()).isEqualTo(13L);
        assertThat(first.high()).isEqualByComparingTo(new BigDecimal("229.98"));
        assertThat(first.low()).isEqualByComparingTo(new BigDecimal("219.38"));
        assertThat(first.close()).isEqualByComparingTo(new BigDecimal("222.64"));

        StockRepository.PriceRow second = rows.get(1);
        assertThat(second.idStock()).isEqualTo(7458L);
        assertThat(second.high()).isEqualByComparingTo(new BigDecimal("6894.87"));
    }

    @Test
    @DisplayName("parsePrices strips thousand-separator commas from price values")
    void parsePrices_stripsCommasFromPrices(@TempDir Path tmp) throws Exception {
        Path csv = tmp.resolve("prices.csv");
        Files.writeString(csv, """
                "id_stock","high","low","close","date"
                "7,458","6,977.27","6,934.07","6,966.28","2026-01-09"
                """, StandardCharsets.UTF_8);

        List<StockRepository.PriceRow> rows = service.parsePrices(csv);
        assertThat(rows.get(0).close()).isEqualByComparingTo(new BigDecimal("6966.28"));
    }

    @Test
    @DisplayName("parsePrices skips malformed rows without aborting")
    void parsePrices_skipsMalformedRows(@TempDir Path tmp) throws Exception {
        Path csv = tmp.resolve("prices.csv");
        Files.writeString(csv, """
                "id_stock","high","low","close","date"
                "13","229.98","219.38","INVALID","2025-01-21"
                "13","229.98","219.38","222.64","2025-01-22"
                """, StandardCharsets.UTF_8);

        List<StockRepository.PriceRow> rows = service.parsePrices(csv);
        assertThat(rows).hasSize(1);
    }
}

package com.project.service;

import com.project.model.MonthlyAverage;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

import java.math.BigDecimal;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;

import static org.assertj.core.api.Assertions.*;

/** Unit tests for {@link MonthlyAverageCsvWriter}. */
@DisplayName("MonthlyAverageCsvWriter")
class MonthlyAverageCsvWriterTest {

    private MonthlyAverageCsvWriter writer;

    @BeforeEach
    void setUp() {
        writer = new MonthlyAverageCsvWriter();
    }

    @Test
    @DisplayName("write produces correct header and data rows")
    void write_correctContent(@TempDir Path tmp) throws Exception {
        Path out = tmp.resolve("monthly_average_prices.csv");
        List<MonthlyAverage> avgs = List.of(
            new MonthlyAverage("AAPL", "JAN", new BigDecimal("222.77")),
            new MonthlyAverage("GOOG", "JAN", new BigDecimal("185.34"))
        );
        writer.write(avgs, out);
        List<String> lines = Files.readAllLines(out, StandardCharsets.UTF_8);
        assertThat(lines.get(0)).isEqualTo("symbol,month,average_price");
        assertThat(lines.get(1)).isEqualTo("AAPL,JAN,222.77");
        assertThat(lines.get(2)).isEqualTo("GOOG,JAN,185.34");
        assertThat(lines).hasSize(3);
    }

    @Test
    @DisplayName("write creates parent directories automatically")
    void write_createsParentDirs(@TempDir Path tmp) throws Exception {
        Path nested = tmp.resolve("sub/dir/out.csv");
        writer.write(List.of(new MonthlyAverage("MSFT", "MAR", new BigDecimal("410.00"))), nested);
        assertThat(Files.exists(nested)).isTrue();
    }

    @Test
    @DisplayName("write produces header-only file for empty list")
    void write_emptyList_headerOnly(@TempDir Path tmp) throws Exception {
        Path out = tmp.resolve("out.csv");
        writer.write(List.of(), out);
        List<String> lines = Files.readAllLines(out, StandardCharsets.UTF_8);
        assertThat(lines).hasSize(1);
        assertThat(lines.get(0)).isEqualTo("symbol,month,average_price");
    }

    @Test
    @DisplayName("write rejects null averages")
    void write_nullAverages_throws(@TempDir Path tmp) {
        assertThatNullPointerException()
            .isThrownBy(() -> writer.write(null, tmp.resolve("out.csv")));
    }

    @Test
    @DisplayName("HEADERS constant matches specification")
    void headers_matchSpec() {
        assertThat(MonthlyAverageCsvWriter.HEADERS)
            .containsExactly("symbol", "month", "average_price");
    }
}

package com.project.service;

import com.project.model.MonthlyAverage;
import com.project.repository.StockRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.junit.jupiter.api.io.TempDir;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.math.BigDecimal;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;

import static org.assertj.core.api.Assertions.*;
import static org.mockito.Mockito.*;

/**
 * Unit tests for {@link MonthlyAverageService}.
 *
 * <p>The {@link StockRepository} and {@link MonthlyAverageCsvWriter} are mocked
 * so tests verify orchestration logic without touching the database or filesystem
 * (except for the @TempDir cases that verify CSV content).</p>
 */
@ExtendWith(MockitoExtension.class)
@DisplayName("MonthlyAverageService")
class MonthlyAverageServiceTest {

    @Mock StockRepository         repository;
    @Mock MonthlyAverageCsvWriter writer;

    private MonthlyAverageService service;

    @BeforeEach
    void setUp() {
        service = new MonthlyAverageService(repository, writer);
    }

    // ── constructor ───────────────────────────────────────────────────────────

    @Test
    @DisplayName("constructor rejects null repository")
    void constructor_rejectsNullRepository() {
        assertThatNullPointerException()
                .isThrownBy(() -> new MonthlyAverageService(null, writer))
                .withMessageContaining("repository");
    }

    @Test
    @DisplayName("constructor rejects null writer")
    void constructor_rejectsNullWriter() {
        assertThatNullPointerException()
                .isThrownBy(() -> new MonthlyAverageService(repository, null))
                .withMessageContaining("writer");
    }

    // ── generateAndSend ───────────────────────────────────────────────────────

    @Test
    @DisplayName("generateAndSend queries the repository and passes results to writer")
    void generateAndSend_queriesAndWrites(@TempDir Path outputDir) throws Exception {
        List<MonthlyAverage> averages = List.of(
                new MonthlyAverage("AAPL", "JAN", new BigDecimal("222.77")),
                new MonthlyAverage("AAPL", "FEB", new BigDecimal("229.61"))
        );
        when(repository.getMonthlyAverages()).thenReturn(averages);

        Path result = service.generateAndSend(outputDir);

        verify(repository, times(1)).getMonthlyAverages();
        verify(writer, times(1)).write(eq(averages), eq(result));
        assertThat(result.getFileName().toString()).isEqualTo("monthly_average_prices.csv");
    }

    @Test
    @DisplayName("generateAndSend returns correct output path inside the given directory")
    void generateAndSend_returnsCorrectPath(@TempDir Path outputDir) throws Exception {
        when(repository.getMonthlyAverages()).thenReturn(List.of());

        Path result = service.generateAndSend(outputDir);

        assertThat(result).isEqualTo(outputDir.resolve("monthly_average_prices.csv"));
    }

    @Test
    @DisplayName("generateAndSend does not throw when query returns empty list")
    void generateAndSend_toleratesEmptyResults(@TempDir Path outputDir) throws Exception {
        when(repository.getMonthlyAverages()).thenReturn(List.of());

        assertThatNoException().isThrownBy(() -> service.generateAndSend(outputDir));
        verify(writer).write(eq(List.of()), any(Path.class));
    }

    @Test
    @DisplayName("generateAndSend rejects null outputDir")
    void generateAndSend_rejectsNullOutputDir() {
        assertThatNullPointerException()
                .isThrownBy(() -> service.generateAndSend(null));
    }

    // ── OUTPUT_FILE constant ──────────────────────────────────────────────────

    @Test
    @DisplayName("OUTPUT_FILE constant matches specification")
    void outputFileConstant_matchesSpec() {
        assertThat(MonthlyAverageService.OUTPUT_FILE).isEqualTo("monthly_average_prices.csv");
    }
}
